export const SURNAMES = ['李'];
export const REALM_ORDER = [Realm.QiRefinement, Realm.FoundationEstablishment, Realm.Zifu, Realm.JinDan, Realm.YuanYing, Realm.YuanShen];

export const PHYSIQUES = ['凡胎俗骨', '纯阳之体', '天生剑心', '九阴绝脉', '厚土灵躯', '长生圣体'];
export const ABILITIES = ['庚金剑气', '离火瞳', '御风术', '厚土盾'];
