        roots: { gold: 0, wood: 0, water: 0, fire: 0, earth: 0 },
        rootGrade: '凡胎', talents: { 战斗天赋: { 剑法: 10, 拳法: 10, 枪法: 10, 刀法: 10, 弓箭: 10 }, 百艺天赋: { 炼丹: 10, 炼器: 10, 制符: 10, 阵法: 10 } },
        tier: '凡人', element: Element.Earth, status: 'healthy', loyalty: 100, assignment: 'Patrol', legacyPoints: 100,
