import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES } from './constants';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import { generateYearlyEvent } from './services/geminiService';

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        spiritStones: 1200,
        merit: 100,
        luck: 50,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: {
            herbs: { "灵谷草": 15, "清灵花": 5, "回气草": 5, "玉露根": 5 },
            minerals: { "精铁": 20 },
            paper: 5,
            pills: {},
            weapons: {}
        },
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。"],
        heritagePool: 0,
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let updatedMembers = [...prev.members];
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            if (updates.position === '老祖') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '老祖' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers.map(m => m.id === id ? { ...m, ...updates } : m)
            };
        });
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (!info || state.spiritStones < info.baseCost) return;
        const newBuilding: Building = {
            id: `build-${Date.now()}`,
            type, level: 1, assignedMemberId: null, isFinished: false, turnsRemaining: info.baseTurns
        };
        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, newBuilding],
            logs: [`【营建】${info.name} 开始破土动工。`, ...prev.logs].slice(0, 15)
        }));
    };

    const handleAssignBuilding = (buildingId: string, memberId: string | null) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => b.id === buildingId ? { ...b, assignedMemberId: memberId } : b)
        }));
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 100;
        let bonusHerbs: Record<string, number> = {};

        const updatedBuildings = state.buildings.map(b => {
            if (!b.isFinished) {
                const remaining = b.turnsRemaining - 1;
                if (remaining <= 0) {
                    yearLogs.push(`【营建】${BUILDING_TYPES[b.type].name} 终于落成！`);
                    return { ...b, isFinished: true, turnsRemaining: 0 };
                }
                return { ...b, turnsRemaining: remaining };
            }
            if (b.type === 'Market' && b.assignedMemberId) stoneGain += 200;
            if (b.type === 'SpiritField') {
                // 灵田随机产出基础药材
                const pool = ["灵谷草", "清灵花", "回气草", "玉露根"];
                const pick = pool[Math.floor(Math.random() * pool.length)];
                bonusHerbs[pick] = (bonusHerbs[pick] || 0) + 10;
            }
            return b;
        });

        const updatedMembers = state.members.map(m => {
            if (m.status === 'dead') return m;
            let nm = { ...m, age: m.age + 1 };
            const hasRoots = Object.values(nm.roots).some(v => v > 0);
            if (nm.assignment === 'Cultivation' && hasRoots) {
                nm.cultivationProgress += (nm.aptitude / 10) + 5;
                if (nm.cultivationProgress >= 100) {
                    nm.cultivationProgress = 0;
                    if (nm.subRealm < 9) nm.subRealm += 1;
                    else {
                        const idx = REALM_ORDER.indexOf(nm.realm);
                        if (idx < REALM_ORDER.length - 1) {
                            nm.realm = REALM_ORDER[idx + 1]; nm.subRealm = 1; nm.maxAge += 100;
                            yearLogs.push(`【突破】${nm.name} 踏入 ${nm.realm} 境界！`);
                        }
                    }
                }
            }
            if (nm.age >= nm.maxAge) {
                nm.status = 'dead'; nm.deathYear = state.year;
                yearLogs.push(`【陨落】家族长辈 ${nm.name} 驾鹤西去。`);
            }
            return nm;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers });

        setState(prev => {
            const newHerbs = { ...prev.inventory.herbs };
            Object.entries(bonusHerbs).forEach(([name, count]) => {
                newHerbs[name] = (newHerbs[name] || 0) + count;
            });
            return {
                ...prev,
                year: prev.year + 1,
                members: updatedMembers,
                buildings: updatedBuildings,
                spiritStones: prev.spiritStones + stoneGain,
                inventory: { ...prev.inventory, herbs: newHerbs },
                logs: [...yearLogs, ...prev.logs].slice(0, 15)
            };
        });
        setEvent(newEvent);
        setIsProcessing(false);
    };

    return (
        <div className="h-screen w-screen flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl">
                <div className="flex items-center gap-12">
                    <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>📜 族谱</button>
                    <button onClick={handleNextYear} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">{isProcessing ? '推演中' : '岁过一载'}</button>
                </div>
            </header>
            <main className="flex-1 flex overflow-hidden">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap regions={state.regions} members={state.members} currentRegionId={state.currentRegionId} onSelectRegion={(r) => setState(p => ({ ...p, currentRegionId: r ? r.id : '' }))} onUpdateMember={handleUpdateMember} onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} />
                    <div className={`absolute bottom-6 left-6 transition-all duration-500 parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-56'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5">
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)} className="text-[#4a3728] hover:text-black">{isConsoleCollapsed ? '▲' : '▼'}</button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-2.5 text-[11px]">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold"><span className="text-[#8b0000] mr-2">◈</span> {log}</p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
                {isDashboardVisible && <div className="w-80 h-full border-l border-yellow-900/50"><ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={() => {}} /></div>}
            </main>
            {isManagementVisible && <ClanManagement state={state} onUpdateMember={handleUpdateMember} onAddBuilding={handleAddBuilding} onAssignBuilding={handleAssignBuilding} onClose={() => setIsManagementVisible(false)} />}
            {event && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-[#f4e4bc] w-full max-w-2xl p-8 rounded border-[12px] border-[#4a3728] shadow-2xl relative">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 py-3 rounded-b-xl font-cursive text-2xl">{event.title}</div>
                        <div className="text-[#2c1810] leading-relaxed text-lg font-serif italic mb-8">{event.content}</div>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceA.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceB.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo } from 'react';
import { GameState, ClanMember, Building, Realm } from '../types';
import { BUILDING_TYPES, POSITIONS, REALM_ORDER, RECIPES } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddBuilding: (type: string) => void;
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    onClose: () => void;
}

const ClanManagement: React.FC<Props> = ({ state, onUpdateMember, onAddBuilding, onAssignBuilding, onClose }) => {
    const [activeTab, setActiveTab] = useState<'status' | 'buildings' | 'positions' | 'alchemy' | 'smithing'>('status');

    const aliveMembers = useMemo(() => state.members.filter(m => m.status !== 'dead'), [state.members]);

    const realmStats = useMemo(() => {
        const stats: Record<string, number> = {};
        let maxRealmIdx = 0;
        aliveMembers.forEach(m => {
            stats[m.realm] = (stats[m.realm] || 0) + 1;
            maxRealmIdx = Math.max(maxRealmIdx, REALM_ORDER.indexOf(m.realm));
        });
        return REALM_ORDER.slice(0, maxRealmIdx + 1).reverse();
    }, [aliveMembers]);

    const totalHerbs = useMemo(() => Object.values(state.inventory.herbs).reduce((a, b) => a + b, 0), [state.inventory.herbs]);
    const totalMinerals = useMemo(() => Object.values(state.inventory.minerals).reduce((a, b) => a + b, 0), [state.inventory.minerals]);

    const hasBuilding = (type: string) => state.buildings.some(b => b.type === type && b.isFinished);

    const getBuildingProgress = (b: Building) => {
        const total = BUILDING_TYPES[b.type].baseTurns;
        const current = total - b.turnsRemaining;
        return (current / total) * 100;
    };

    const renderBuildingList = (category: string) => {
        const list = Object.entries(BUILDING_TYPES).filter(([_, info]) => info.category === category);
        return (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {list.map(([type, info]) => {
                    const existing = state.buildings.find(b => b.type === type);
                    const canBuild = !existing && state.spiritStones >= info.baseCost;
                    let reqMet = true;
                    if (info.requirements.realm) {
                        reqMet = aliveMembers.some(m => REALM_ORDER.indexOf(m.realm) >= REALM_ORDER.indexOf(info.requirements.realm!));
                    }
                    if (info.requirements.talent) {
                        const { type: tType, rank } = info.requirements.talent;
                        reqMet = reqMet && aliveMembers.some(m => m.talents.百艺天赋[tType] >= rank);
                    }

                    return (
                        <div key={type} className={`p-4 rounded border transition-all ${existing ? 'bg-black/40 border-yellow-900/30' : 'bg-[#2c1810]/30 border-yellow-900/10'}`}>
                            <div className="flex justify-between items-center mb-2">
                                <span className="text-sm font-bold text-yellow-500">{info.icon} {info.name}</span>
                                <span className="text-[10px] text-yellow-800">✨ {info.baseCost} | ⏳ {info.baseTurns}y</span>
                            </div>
                            <p className="text-[10px] text-gray-500 mb-3">{info.desc}</p>
                            {existing ? (
                                existing.isFinished ? (
                                    <div className="text-[10px] text-green-600 font-bold">已落成</div>
                                ) : (
                                    <div className="w-full h-1.5 bg-black/60 rounded-full overflow-hidden">
                                        <div className="h-full bg-yellow-600 animate-pulse" style={{ width: `${getBuildingProgress(existing)}%` }}></div>
                                    </div>
                                )
                            ) : (
                                <button onClick={() => onAddBuilding(type)} disabled={!canBuild || !reqMet} className={`w-full py-1 text-[10px] rounded border transition-all ${canBuild && reqMet ? 'bg-yellow-900/20 border-yellow-700 text-yellow-400 hover:bg-yellow-700 hover:text-white' : 'bg-gray-800/20 border-gray-700 text-gray-600 opacity-50 cursor-not-allowed'}`}>
                                    {!reqMet ? '资质不足' : '立即营造'}
                                </button>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 overflow-hidden">
            <div className="relative w-full max-w-6xl h-[85vh] bg-[#1a1310] border-[6px] border-[#4a3728] rounded-sm shadow-2xl flex flex-col">
                <div className="h-14 bg-[#2c1810] border-b border-yellow-900/30 flex items-center px-6 shrink-0 gap-8">
                    <h2 className="text-xl font-cursive text-yellow-500">🏯 望月大社</h2>
                    <div className="flex h-full">
                        <button onClick={() => setActiveTab('status')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'status' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>家族概况</button>
                        <button onClick={() => setActiveTab('buildings')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'buildings' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>建筑营造</button>
                        <button onClick={() => setActiveTab('positions')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'positions' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>职位册封</button>
                        {hasBuilding('AlchemyRoom') && <button onClick={() => setActiveTab('alchemy')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'alchemy' ? 'border-pink-500 text-pink-500 bg-pink-900/10' : 'border-transparent text-gray-500'}`}>炼丹</button>}
                        {hasBuilding('Smithy') && <button onClick={() => setActiveTab('smithing')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'smithing' ? 'border-blue-500 text-blue-500 bg-blue-900/10' : 'border-transparent text-gray-500'}`}>炼器</button>}
                    </div>
                    <button onClick={onClose} className="ml-auto w-8 h-8 flex items-center justify-center text-gray-500 hover:text-white text-2xl">×</button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                    {activeTab === 'status' && (
                        <div className="space-y-8 animate-fade-in">
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <div className="p-4 bg-black/30 border border-yellow-900/20 rounded">
                                    <h3 className="text-yellow-600 text-[10px] font-bold uppercase mb-4 tracking-widest">资源统计</h3>
                                    <div className="space-y-2 text-sm">
                                        <div className="flex justify-between"><span className="text-gray-500">家族灵石</span><span className="text-yellow-400 font-bold">{state.spiritStones}</span></div>
                                        <div className="flex justify-between"><span className="text-gray-500">功德点</span><span className="text-blue-400 font-bold">{state.merit}</span></div>
                                        <div className="flex justify-between"><span className="text-gray-500">家族底蕴</span><span className="text-purple-400 font-bold">{state.heritagePool}</span></div>
                                    </div>
                                </div>
                                <div className="p-4 bg-black/30 border border-yellow-900/20 rounded">
                                    <h3 className="text-blue-600 text-[10px] font-bold uppercase mb-4 tracking-widest">境界分布</h3>
                                    <div className="space-y-2 text-sm">
                                        {realmStats.map(r => (
                                            <div key={r} className="flex justify-between"><span className="text-gray-500">{r}</span><span className="text-gray-200">{state.members.filter(m => m.status !== 'dead' && m.realm === r).length} 人</span></div>
                                        ))}
                                    </div>
                                </div>
                                <div className="p-4 bg-black/30 border border-yellow-900/20 rounded">
                                    <h3 className="text-green-600 text-[10px] font-bold uppercase mb-4 tracking-widest">物产仓库</h3>
                                    <div className="space-y-2 text-sm">
                                        <div className="flex justify-between"><span className="text-gray-500">药材总量</span><span className="text-green-400 font-bold">{totalHerbs}</span></div>
                                        <div className="flex justify-between"><span className="text-gray-500">矿石总量</span><span className="text-gray-400 font-bold">{totalMinerals}</span></div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'buildings' && (
                        <div className="space-y-8 animate-fade-in">
                            <div><h3 className="text-yellow-700 text-xs font-bold mb-4 border-l-4 border-yellow-700 pl-3">资源建筑 (Resource)</h3>{renderBuildingList('Resource')}</div>
                            <div><h3 className="text-blue-700 text-xs font-bold mb-4 border-l-4 border-blue-700 pl-3">功能建筑 (Functional)</h3>{renderBuildingList('Functional')}</div>
                            <div><h3 className="text-emerald-700 text-xs font-bold mb-4 border-l-4 border-emerald-700 pl-3">基础建筑 (Base)</h3>{renderBuildingList('Base')}</div>
                        </div>
                    )}
                    {activeTab === 'alchemy' && (
                        <div className="flex gap-6 h-full animate-fade-in">
                            <div className="w-1/3 p-4 bg-black/40 border border-pink-900/20 rounded">
                                <h3 className="text-pink-500 font-bold text-sm mb-4">⚗️ 炼丹室状态</h3>
                                <div className="text-xs text-gray-500 space-y-4">
                                    <p>当前等级: 1</p>
                                    <p>派驻炼丹师: {state.buildings.find(b => b.type === 'AlchemyRoom')?.assignedMemberId ? state.members.find(m => m.id === state.buildings.find(b => b.type === 'AlchemyRoom')?.assignedMemberId)?.name : '暂无'}</p>
                                    <div className="pt-4"><span className="text-[10px] text-gray-600">分配人员:</span><select className="w-full mt-1 bg-[#2c1810] border border-yellow-900/30 p-1 rounded text-yellow-500" onChange={(e) => onAssignBuilding(state.buildings.find(b => b.type === 'AlchemyRoom')!.id, e.target.value || null)} value={state.buildings.find(b => b.type === 'AlchemyRoom')?.assignedMemberId || ''}><option value="">- 轮空 -</option>{aliveMembers.map(m => <option key={m.id} value={m.id}>{m.name} ({m.realm})</option>)}</select></div>
                                </div>
                            </div>
                            <div className="flex-1 p-4 bg-black/20 border border-white/5 rounded overflow-y-auto">
                                <h3 className="text-gray-400 font-bold text-sm mb-4">📖 家族丹方</h3>
                                <div className="grid grid-cols-2 gap-4">
                                    {(RECIPES.Alchemy as any[]).map(r => (
                                        <div key={r.name} className="p-3 border border-yellow-900/10 bg-black/40 rounded flex flex-col justify-between">
                                            <div>
                                                <div className="flex justify-between items-center mb-2"><span className="text-yellow-500 font-bold">{r.name}</span><span className="text-[10px] text-gray-600">Lvl {r.level}</span></div>
                                                <p className="text-[10px] text-gray-500 italic mb-2">"{r.effect}"</p>
                                                <div className="text-[9px] text-pink-700">所需: {Object.entries(r.cost).map(([k,v]) => `${k} x${v}`).join(' | ')}</div>
                                            </div>
                                            <button className="mt-4 w-full py-1 bg-pink-900/20 hover:bg-pink-800 border border-pink-700 text-pink-500 hover:text-white text-[10px] rounded">开始炼制</button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'positions' && (
                        <div className="grid grid-cols-3 gap-4 animate-fade-in">
                            {aliveMembers.map(m => (
                                <div key={m.id} className="p-3 bg-black/40 border border-yellow-900/10 rounded flex justify-between items-center">
                                    <div><p className="text-sm font-bold text-yellow-100">{m.name}</p><p className="text-[10px] text-gray-600">{m.realm}{m.subRealm}层</p></div>
                                    <select className="bg-[#2c1810] border border-yellow-900/20 p-1 text-[10px] text-orange-400 rounded outline-none" value={m.position} onChange={(e) => onUpdateMember(m.id, { position: e.target.value })}>{POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}</select>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

