                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">当前寿元：</span><span className={`font-bold ${selectedMember.maxAge - selectedMember.age < 10 ? 'text-red-500 animate-pulse' : 'text-green-400'}`}>{selectedMember.age} / {selectedMember.maxAge} 载</span></div>
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">职位：</span><span className="text-orange-400 font-bold">{selectedMember.position}</span></div>
                                            </div>
                                        </div>
                                        <div>
                                            <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">魂质天赋</h4>
                                            <div className="grid grid-cols-2 gap-4 text-xs sm:text-sm">
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">修行资质：</span><span className="text-yellow-500 font-bold">{selectedMember.aptitude}</span></div>
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">特殊体质：</span><span onMouseEnter={(e) => showTooltip(e, renderPhysiqueTooltipContent(selectedMember.physique))} onMouseLeave={hideTooltip} className="text-pink-500 font-bold cursor-help underline underline-offset-4 decoration-dotted">{selectedMember.physique}</span></div>
                                            </div>
                                        </div>
                                    </div>
                                    <div>
                                        <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">修为进度：{selectedMember.realm} {selectedMember.subRealm}层</h4>
                                        <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10">
                                            <div className="h-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)] transition-all" style={{ width: `${selectedMember.cultivationProgress}%` }}></div>
                                        </div>
                                    </div>
                                </div>
                            )}
                            {detailTab === 'talents' && (
                                <div className="space-y-8 animate-fade-in text-white">
                                    <div>
                                        <h4 className="text-red-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-red-900/10 pb-2 mb-4">⚔️ 战斗造诣 (1-10)</h4>
                                        <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                                            {(Object.entries(selectedMember.talents.战斗天赋) as [string, number][]).map(([key, val]) => (
                                                <div key={key} className="bg-black/20 p-2 sm:p-3 rounded-lg border border-white/5 text-center">
                                                    <p className="text-[10px] text-gray-500">{key}</p>
                                                    <p className="text-lg font-bold text-red-400">{val}</p>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                    <div>
                                        <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">🧪 百艺修持 (1-10)</h4>
                                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                                            {(Object.entries(selectedMember.talents.百艺天赋) as [string, number][]).map(([key, val]) => {
                                                const title = getArtisanTitle(key, val, selectedMember.realm);
                                                const bonus = getArtisanBonus(val);
                                                return (
                                                    <div key={key} className="bg-black/30 p-4 rounded-lg border border-blue-900/20 relative group overflow-hidden">
                                                        <div className="flex justify-between items-center mb-2">
                                                            <span className="text-xs text-gray-400">{key}</span>
                                                            <span className="text-xl font-bold text-blue-400 font-mono">{val}</span>
                                                        </div>
                                                        <p className="text-sm font-bold text-yellow-500 mb-1">{title}</p>
                                                        {bonus > 0 && <p className="text-[10px] text-green-500">成功率 +{bonus}%</p>}
                                                        <div className="absolute -bottom-2 -right-2 opacity-5 text-4xl group-hover:scale-110 transition-all">⚙️</div>
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    </div>
                                </div>
                            )}
                            {detailTab === 'cultivation' && (
                                <div className="flex-1 flex flex-col sm:flex-row bg-[#0c1310] relative animate-fade-in overflow-hidden h-full rounded-lg">
                                    <div className="w-full sm:w-[40%] p-4 flex flex-col items-center justify-center border-b sm:border-b-0 sm:border-r border-white/5 overflow-y-auto shrink-0">
                                        <div className="relative w-full flex flex-col items-center justify-center gap-4 sm:gap-6 py-4">
                                            {renderSlotItem(selectedMember.movementMethodId, 'Movement', '遁术', 'mov')}
                                            <div className="flex items-center gap-4 sm:gap-8">
                                                <div className="flex flex-col gap-2 sm:gap-4">
                                                    {renderSlotItem(selectedMember.auxMethodIds[0] || null, 'Combat', '辅修', 'aux0')}
                                                    {renderSlotItem(selectedMember.auxMethodIds[1] || null, 'Combat', '辅修', 'aux1')}
                                                </div>
                                                <div className="w-16 h-16 sm:w-24 sm:h-24 relative flex items-center justify-center shrink-0">
                                                    <div className="text-4xl sm:text-6xl opacity-30 animate-pulse">🧘</div>
                                                </div>
                                                <div className="flex flex-col gap-2 sm:gap-4">
                                                    {renderSlotItem(selectedMember.auxMethodIds[2] || null, 'Combat', '辅修', 'aux2')}
                                                    {renderSlotItem(selectedMember.auxMethodIds[3] || null, 'Combat', '辅修', 'aux3')}
                                                </div>
                                            </div>
                                            {renderSlotItem(selectedMember.mainMethodId, 'Cultivation', '主修', 'main')}
                                        </div>
                                    </div>
                                    <div className="flex-1 p-4 bg-black/20 flex flex-col overflow-hidden">
                                        <div className="flex justify-between items-center mb-4 shrink-0">
                                            <div className="flex gap-1 p-1 bg-black/40 rounded-lg border border-yellow-900/20">
                                                <button onClick={() => setLibraryType('Cultivation')} className={`px-4 py-1 text-xs rounded transition-all ${libraryType === 'Cultivation' ? 'bg-yellow-800 text-yellow-100 font-bold' : 'text-gray-500'}`}>修行</button>
                                                <button onClick={() => setLibraryType('Combat')} className={`px-4 py-1 text-xs rounded transition-all ${libraryType === 'Combat' ? 'bg-red-900 text-yellow-100 font-bold' : 'text-gray-500'}`}>战斗</button>
                                                <button onClick={() => setLibraryType('Movement')} className={`px-4 py-1 text-xs rounded transition-all ${libraryType === 'Movement' ? 'bg-blue-900 text-yellow-100 font-bold' : 'text-gray-500'}`}>遁术</button>
                                            </div>
                                        </div>
                                        <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar grid grid-cols-2 md:grid-cols-4 gap-4 pb-8">
                                            {libraryMethods.map(method => {
                                                const isEquipped = selectedMember.mainMethodId === method.id || selectedMember.movementMethodId === method.id || selectedMember.auxMethodIds.includes(method.id);
                                                return (
                                                    <div key={method.id} className="relative group">
                                                        <button onClick={() => !isEquipped && toggleMethod(method.id, method.type)}
                                                            className={`w-full aspect-square rounded border-2 p-2 flex flex-col items-center justify-center gap-1 transition-all ${getGradeColor(method.grade)} ${isEquipped ? 'ring-1 ring-yellow-500 brightness-75' : 'opacity-70 hover:opacity-100'}`}>
                                                            {isEquipped && <div className="absolute -top-1 -right-1 w-3 h-3 bg-yellow-500 text-black text-[8px] rounded-full flex items-center justify-center font-bold">✓</div>}
                                                            <span className="text-[10px] font-bold text-center leading-tight">{method.name}</span>
                                                        </button>
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;

import React, { useState, useMemo } from 'react';
import { GameState, ClanMember, Building, Realm } from '../types';
import { BUILDING_TYPES, POSITIONS, REALM_ORDER, RECIPES, getArtisanTitle, getArtisanBonus } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddBuilding: (type: string) => void;
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    onClose: () => void;
}

const ClanManagement: React.FC<Props> = ({ state, onUpdateMember, onAddBuilding, onAssignBuilding, onClose }) => {
    const [activeTab, setActiveTab] = useState<'status' | 'buildings' | 'positions' | 'alchemy' | 'smithing'>('status');
    const aliveMembers = useMemo(() => state.members.filter(m => m.status !== 'dead'), [state.members]);

    const hasBuilding = (type: string) => state.buildings.some(b => b.type === type && b.isFinished);
    const getBuildingProgress = (b: Building) => {
        const total = BUILDING_TYPES[b.type].baseTurns;
        const current = total - b.turnsRemaining;
        return (current / total) * 100;
    };

    const alchemyRoom = state.buildings.find(b => b.type === 'AlchemyRoom');
    const assignedAlchemist = aliveMembers.find(m => m.id === alchemyRoom?.assignedMemberId);

    const smithyRoom = state.buildings.find(b => b.type === 'Smithy');
    const assignedSmith = aliveMembers.find(m => m.id === smithyRoom?.assignedMemberId);

    const renderBuildingList = (category: string) => {
        const list = Object.entries(BUILDING_TYPES).filter(([_, info]) => info.category === category);
        return (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {list.map(([type, info]) => {
                    const existing = state.buildings.find(b => b.type === type);
                    const canBuild = !existing && state.spiritStones >= info.baseCost;
                    return (
                        <div key={type} className={`p-4 rounded border transition-all ${existing ? 'bg-black/40 border-yellow-900/30' : 'bg-[#2c1810]/30 border-yellow-900/10'}`}>
                            <div className="flex justify-between items-center mb-2">
                                <span className="text-sm font-bold text-yellow-500">{info.icon} {info.name}</span>
                                <span className="text-[10px] text-yellow-800">✨ {info.baseCost} | ⏳ {info.baseTurns}y</span>
                            </div>
                            <p className="text-[10px] text-gray-500 mb-3">{info.desc}</p>
                            {existing ? (
                                existing.isFinished ? <div className="text-[10px] text-green-600 font-bold">已落成</div> :
                                <div className="w-full h-1.5 bg-black/60 rounded-full overflow-hidden">
                                    <div className="h-full bg-yellow-600 animate-pulse" style={{ width: `${getBuildingProgress(existing)}%` }}></div>
                                </div>
                            ) : (
                                <button onClick={() => onAddBuilding(type)} disabled={!canBuild} className={`w-full py-1 text-[10px] rounded border transition-all ${canBuild ? 'bg-yellow-900/20 border-yellow-700 text-yellow-400 hover:bg-yellow-700 hover:text-white' : 'bg-gray-800/20 border-gray-700 text-gray-600 opacity-50 cursor-not-allowed'}`}>
                                    营造
                                </button>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 overflow-hidden">
            <div className="relative w-full max-w-6xl h-[85vh] bg-[#1a1310] border-[6px] border-[#4a3728] rounded-sm shadow-2xl flex flex-col">
                <div className="h-14 bg-[#2c1810] border-b border-yellow-900/30 flex items-center px-6 shrink-0 gap-8">
                    <h2 className="text-xl font-cursive text-yellow-500">🏯 望月大社</h2>
                    <div className="flex h-full">
                        <button onClick={() => setActiveTab('status')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'status' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>概况</button>
                        <button onClick={() => setActiveTab('buildings')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'buildings' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>营造</button>
                        {hasBuilding('AlchemyRoom') && <button onClick={() => setActiveTab('alchemy')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'alchemy' ? 'border-pink-500 text-pink-500 bg-pink-900/10' : 'border-transparent text-gray-500'}`}>炼丹</button>}
                        {hasBuilding('Smithy') && <button onClick={() => setActiveTab('smithing')} className={`px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'smithing' ? 'border-blue-500 text-blue-500 bg-blue-900/10' : 'border-transparent text-gray-500'}`}>炼器</button>}
                    </div>
                    <button onClick={onClose} className="ml-auto w-8 h-8 flex items-center justify-center text-gray-500 hover:text-white text-2xl">×</button>
                </div>

                <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                    {activeTab === 'alchemy' && (
                        <div className="flex gap-6 h-full animate-fade-in">
                            <div className="w-1/3 p-4 bg-black/40 border border-pink-900/20 rounded">
                                <h3 className="text-pink-500 font-bold text-sm mb-4">⚗️ 丹鼎堂</h3>
                                <div className="text-xs text-gray-500 space-y-4">
                                    <div className="bg-pink-900/10 p-3 rounded border border-pink-900/20">
                                        <p className="text-gray-400 mb-1">当前主事:</p>
                                        {assignedAlchemist ? (
                                            <div>
                                                <p className="text-yellow-500 font-bold text-sm">{assignedAlchemist.name}</p>
                                                <p className="text-pink-400 text-[10px] mt-1">
                                                    {getArtisanTitle('炼丹', assignedAlchemist.talents.百艺天赋.炼丹, assignedAlchemist.realm)}
                                                </p>
                                                {getArtisanBonus(assignedAlchemist.talents.百艺天赋.炼丹) > 0 && (
                                                    <p className="text-green-500 text-[9px] mt-1">
                                                        成功率加成: +{getArtisanBonus(assignedAlchemist.talents.百艺天赋.炼丹)}%
                                                    </p>
                                                )}
                                            </div>
                                        ) : <p className="italic text-gray-600">暂未指派</p>}
                                    </div>
                                    <select className="w-full mt-1 bg-[#2c1810] border border-yellow-900/30 p-1 rounded text-yellow-500" 
                                        onChange={(e) => onAssignBuilding(alchemyRoom!.id, e.target.value || null)} 
                                        value={alchemyRoom?.assignedMemberId || ''}>
                                        <option value="">- 指派人员 -</option>
                                        {aliveMembers.map(m => <option key={m.id} value={m.id}>{m.name} ({m.realm})</option>)}
                                    </select>
                                </div>
                            </div>
                            <div className="flex-1 p-4 bg-black/20 border border-white/5 rounded overflow-y-auto">
                                <h3 className="text-gray-400 font-bold text-sm mb-4">📖 丹方集</h3>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                    {(RECIPES.Alchemy as any[]).map(r => (
                                        <div key={r.name} className="p-4 border border-yellow-900/10 bg-black/40 rounded flex flex-col justify-between">
                                            <div>
                                                <div className="flex justify-between items-center mb-1"><span className="text-yellow-500 font-bold">{r.name}</span><span className="text-[10px] text-gray-600">Lvl {r.level}</span></div>
                                                <p className="text-[10px] text-gray-500 mb-2 italic">"{r.effect}"</p>
                                                <div className="text-[9px] text-pink-700">材料: {Object.entries(r.cost).map(([k,v]) => `${k}x${v}`).join(', ')}</div>
                                            </div>
                                            <button className="mt-4 w-full py-1.5 bg-pink-900/20 hover:bg-pink-800 border border-pink-700 text-pink-500 hover:text-white text-xs rounded transition-all">开始炼制</button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'smithing' && (
                        <div className="flex gap-6 h-full animate-fade-in">
                            <div className="w-1/3 p-4 bg-black/40 border border-blue-900/20 rounded">
                                <h3 className="text-blue-500 font-bold text-sm mb-4">🔨 炼器坊</h3>
                                <div className="bg-blue-900/10 p-3 rounded border border-blue-900/20">
                                    <p className="text-gray-400 mb-1">当前主事:</p>
                                    {assignedSmith ? (
                                        <div>
                                            <p className="text-yellow-500 font-bold text-sm">{assignedSmith.name}</p>
                                            <p className="text-blue-400 text-[10px] mt-1">
                                                {getArtisanTitle('炼器', assignedSmith.talents.百艺天赋.炼器, assignedSmith.realm)}
                                            </p>
                                            {getArtisanBonus(assignedSmith.talents.百艺天赋.炼器) > 0 && (
                                                <p className="text-green-500 text-[9px] mt-1">
                                                    成功率加成: +{getArtisanBonus(assignedSmith.talents.百艺天赋.炼器)}%
                                                </p>
                                            )}
                                        </div>
                                    ) : <p className="italic text-gray-600">暂未指派</p>}
                                </div>
                                <select className="w-full mt-4 bg-[#2c1810] border border-yellow-900/30 p-1 rounded text-yellow-500" 
                                    onChange={(e) => onAssignBuilding(smithyRoom!.id, e.target.value || null)} 
                                    value={smithyRoom?.assignedMemberId || ''}>
                                    <option value="">- 指派人员 -</option>
                                    {aliveMembers.map(m => <option key={m.id} value={m.id}>{m.name} ({m.realm})</option>)}
                                </select>
                            </div>
                            <div className="flex-1 p-4 bg-black/20 border border-white/5 rounded overflow-y-auto">
                                <h3 className="text-gray-400 font-bold text-sm mb-4">⚔️ 兵仗谱</h3>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                    {(RECIPES.Smithing as any[]).map(r => (
                                        <div key={r.name} className="p-4 border border-yellow-900/10 bg-black/40 rounded flex flex-col justify-between">
                                            <div>
                                                <div className="flex justify-between items-center mb-1"><span className="text-blue-400 font-bold">{r.name}</span><span className="text-[10px] text-gray-600">Lvl {r.level}</span></div>
                                                <p className="text-[10px] text-gray-500 mb-2 italic">"{r.effect}"</p>
                                                <div className="text-[9px] text-blue-700">材料: {Object.entries(r.cost).map(([k,v]) => `${k}x${v}`).join(', ')}</div>
                                            </div>
                                            <button className="mt-4 w-full py-1.5 bg-blue-900/20 hover:bg-blue-800 border border-blue-700 text-blue-500 hover:text-white text-xs rounded transition-all">锻造</button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'status' && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in">
                            <div className="p-6 bg-black/30 border border-yellow-900/20 rounded-lg">
                                <h3 className="text-yellow-600 text-xs font-bold uppercase mb-4 tracking-widest">宗族资源</h3>
                                <div className="space-y-3">
                                    <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">灵石储备</span><span className="text-yellow-400 font-bold">✨ {state.spiritStones}</span></div>
                                    <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">功德气运</span><span className="text-blue-400 font-bold">☯️ {state.merit}</span></div>
                                </div>
                            </div>
                            <div className="p-6 bg-black/30 border border-yellow-900/20 rounded-lg">
                                <h3 className="text-blue-600 text-xs font-bold uppercase mb-4 tracking-widest">族内主事</h3>
                                <div className="space-y-3">
                                    <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">家主</span><span className="text-gray-200">{aliveMembers.find(m => m.position === '家主')?.name || '暂缺'}</span></div>
                                    <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">炼丹师</span><span className="text-pink-400">{assignedAlchemist?.name || '暂缺'}</span></div>
                                    <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">炼器师</span><span className="text-blue-400">{assignedSmith?.name || '暂缺'}</span></div>
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'buildings' && renderBuildingList('Resource')}
                </div>
            </div>
        </div>
    );
};

