                                <h3 className="text-gray-400 font-bold text-sm mb-4">⚔️ 兵仗谱</h3>
                                <div className="grid grid-cols-2 gap-4">
                                    {(RECIPES.Smithing as any[]).map(r => (
                                        <div key={r.name} className="p-3 border border-yellow-900/10 bg-black/40 rounded flex flex-col justify-between text-white">
                                            <div>
                                                <div className="flex justify-between items-center mb-2"><span className="text-blue-400 font-bold">{r.name}</span><span className="text-[10px] text-gray-600">Lvl {r.level}</span></div>
                                                <p className="text-[10px] text-gray-500 italic mb-2">"{r.effect}"</p>
                                                <div className="text-[9px] text-blue-700">所需: {Object.entries(r.cost).map(([k,v]) => `${k} x${v}`).join(' | ')}</div>
                                            </div>
                                            <button className="mt-4 w-full py-1 bg-blue-900/20 hover:bg-blue-800 border border-blue-700 text-blue-500 hover:text-white text-[10px] rounded">锻造法宝</button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'positions' && (
                        <div className="grid grid-cols-3 gap-4 animate-fade-in">
                            {aliveMembers.map(m => (
                                <div key={m.id} className="p-3 bg-black/40 border border-yellow-900/10 rounded flex justify-between items-center">
                                    <div><p className="text-sm font-bold text-yellow-100">{m.name}</p><p className="text-[10px] text-gray-600">{m.realm}{m.subRealm}层</p></div>
                                    <select className="bg-[#2c1810] border border-yellow-900/20 p-1 text-[10px] text-orange-400 rounded outline-none" value={m.position} onChange={(e) => onUpdateMember(m.id, { position: e.target.value })}>{POSITIONS.map(p => <option key={p} value={p}>{p}</option>)}</select>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default ClanManagement;

export enum Realm {
    Mortal = '凡人',
    QiRefinement = '练气',
    FoundationEstablishment = '筑基',
    Zifu = '紫府',
    JinDan = '金丹',
    YuanYing = '元婴',
    YuanShen = '元神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type TaskType = 'Cultivation' | 'Exploration' | 'Research' | 'Patrol' | 'Idle' | 'Mission';
export type TalentTier = '凡人' | '庸才' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
export type RootGrade = '凡胎' | '伪灵根' | '下品灵根' | '中品灵根' | '极品灵根';
export type DevelopmentPlan = 'Combat' | 'Alchemy' | 'Smithing' | 'Talisman' | 'Balanced';
export type MethodQuality = '上等' | '中等' | '下等';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

export type BuildingCategory = 'Resource' | 'Functional' | 'Base';

export interface Building {
    id: string;
    type: string;
    level: number;
    assignedMemberId: string | null;
    isFinished: boolean;
    turnsRemaining: number;
}

export interface Inventory {
    herbs: Record<string, number>;
    minerals: Record<string, number>;
    paper: number;
    pills: Record<string, number>;
    weapons: Record<string, number>;
}

export interface MethodBuffs {
    cultivationSpeed?: number;
    attack?: number;
    defense?: number;
    divineSense?: number;
    maxAge?: number;
}

export interface CultivationMethod {
    id: string;
    name: string;
    grade: number;
    quality: MethodQuality;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
    buffs: MethodBuffs;
}

export interface ElementalRoots {
    gold: number;
    wood: number;
    water: number;
    fire: number;
    earth: number;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    gender: '男' | '女';
    generation: number; 
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;
    aptitude: number;
    comprehension: number;
    divineSense: number;
    roots: ElementalRoots;
    rootGrade: RootGrade;
    talents: SpecializedTalents;
    tier: TalentTier;

    element: Element;
    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    birthYear: number;
    deathYear?: number;

    mainMethodId: string | null;
    movementMethodId: string | null;
    auxMethodIds: string[];
    cultivationProgress: number;
    developmentPlan: DevelopmentPlan;
    divineAbilities: string[];
    sect: string;
    position: string;
}

export type RegionCategory = 'Natural' | 'Stakeholder' | 'Mystic';
export type RegionType = 'lake' | 'mountain' | 'forest' | 'city' | 'sect' | 'ruins' | 'cave';

export interface Region {
    id: string;
    name: string;
    description: string;
    difficulty: number;
    owner: string;
    x: number;
    y: number;
    type: RegionType;
    category: RegionCategory;
    isDiscovered: boolean;
    resources: string[];

    activeMission?: {
        memberId: string;
        turnsRemaining: number;
        totalTurns: number;
    };
}

export interface GameState {
    year: number;
    spiritStones: number;
    merit: number; 
    luck: number; 
    members: ClanMember[];
    regions: Region[];
    buildings: Building[];
    inventory: Inventory;
    currentRegionId: string;
    isMirrorActive: boolean;
    logs: string[];
    heritagePool: number;
}

import React, { useState, useCallback } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Element, RootGrade, TalentTier } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, GENERATIONS, SURNAMES, PHYSIQUES } from './constants';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import { generateYearlyEvent } from './services/geminiService';

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        spiritStones: 1200,
        merit: 100,
        luck: 50,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: {
            herbs: { "灵谷草": 15, "清灵花": 5, "回气草": 5, "玉露根": 5 },
            minerals: { "精铁": 20 },
            paper: 5,
            pills: {},
            weapons: {}
        },
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。"],
        heritagePool: 0,
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let updatedMembers = [...prev.members];
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            if (updates.position === '老祖') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '老祖' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers.map(m => m.id === id ? { ...m, ...updates } : m)
            };
        });
    };

    const handleAddMember = useCallback(() => {
        setState(prev => {
            // 确定代数和名字
            const lastGen = Math.max(...prev.members.map(m => m.generation));
            const generation = lastGen + 1;
            const genChar = GENERATIONS[generation % GENERATIONS.length];
            const randomChar = String.fromCharCode(0x4e00 + Math.floor(Math.random() * 20000)); // 随机汉字作为名
            const name = `${SURNAMES[0]}${genChar}${randomChar.slice(0,1)}`;

            // 随机灵根生成 (20% 概率有灵根)
            const hasRoots = Math.random() < 0.2;
            const roots = { gold: 0, wood: 0, water: 0, fire: 0, earth: 0 };
            let rootGrade: RootGrade = '凡胎';
            let realm = Realm.Mortal;
            let aptitude = 1;

            if (hasRoots) {
                const elements: (keyof typeof roots)[] = ['gold', 'wood', 'water', 'fire', 'earth'];
                const numElements = Math.floor(Math.random() * 3) + 1;
                for(let i=0; i<numElements; i++) {
                    const el = elements[Math.floor(Math.random()*5)];
                    roots[el] = Math.floor(Math.random() * 10) + 1;
                }
                const total = Object.values(roots).reduce((a,b)=>a+b, 0);
                if (total > 15) rootGrade = '极品灵根';
                else if (total > 10) rootGrade = '中品灵根';
                else if (total > 5) rootGrade = '下品灵根';
                else rootGrade = '伪灵根';

                realm = Realm.QiRefinement;
                aptitude = total * 5 + Math.floor(Math.random() * 20);
            }

            const tier: TalentTier = aptitude > 80 ? '绝世' : aptitude > 60 ? '天才' : aptitude > 40 ? '普通' : '凡人';

            const newMember: ClanMember = {
                id: `mem-${Date.now()}`,
                name,
                gender: Math.random() > 0.5 ? '男' : '女',
                generation,
                realm,
                subRealm: 1,
                age: 0,
                maxAge: 60 + Math.floor(Math.random() * 20),
                physique: hasRoots ? PHYSIQUES[Math.floor(Math.random() * PHYSIQUES.length)] : '凡人',
                aptitude,
                comprehension: Math.floor(Math.random() * 50) + 10,
                divineSense: 0,
                roots,
                rootGrade,
                talents: {
                    战斗天赋: { 剑法: 1, 拳法: 1, 枪法: 1, 刀法: 1, 弓箭: 1 },
                    百艺天赋: { 炼丹: 1, 炼器: 1,制符: 1, 阵法: 1 }
                },
                tier,
                element: Element.Earth,
                status: 'healthy',
                loyalty: 100,
                assignment: 'Idle',
                legacyPoints: 0,
                birthYear: prev.year,
                mainMethodId: null,
                movementMethodId: null,
                auxMethodIds: [],
                cultivationProgress: 0,
                developmentPlan: 'Balanced',
                divineAbilities: [],
                sect: '望月李氏',
                position: '弟子'
            };

            return {
                ...prev,
                members: [...prev.members, newMember],
                logs: [`【添丁】家族新成员 ${name} 呱呱坠地。`, ...prev.logs].slice(0, 15)
            };
        });
    }, [state.year]);

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (!info || state.spiritStones < info.baseCost) return;
        const newBuilding: Building = {
            id: `build-${Date.now()}`,
            type, level: 1, assignedMemberId: null, isFinished: false, turnsRemaining: info.baseTurns
        };
        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, newBuilding],
            logs: [`【营建】${info.name} 开始破土动工。`, ...prev.logs].slice(0, 15)
        }));
    };

    const handleAssignBuilding = (buildingId: string, memberId: string | null) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => b.id === buildingId ? { ...b, assignedMemberId: memberId } : b)
        }));
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 100;
        let bonusHerbs: Record<string, number> = {};

        const updatedBuildings = state.buildings.map(b => {
            if (!b.isFinished) {
                const remaining = b.turnsRemaining - 1;
                if (remaining <= 0) {
                    yearLogs.push(`【营建】${BUILDING_TYPES[b.type].name} 终于落成！`);
                    return { ...b, isFinished: true, turnsRemaining: 0 };
                }
                return { ...b, turnsRemaining: remaining };
            }
            if (b.type === 'Market' && b.assignedMemberId) stoneGain += 200;
            if (b.type === 'SpiritField') {
                const pool = ["灵谷草", "清灵花", "回气草", "玉露根"];
                const pick = pool[Math.floor(Math.random() * pool.length)];
                bonusHerbs[pick] = (bonusHerbs[pick] || 0) + 10;
            }
            return b;
        });

        const updatedMembers = state.members.map(m => {
            if (m.status === 'dead') return m;
            let nm = { ...m, age: m.age + 1 };

            // 灵根判定：五行皆无即凡人
            const totalRoots = Object.values(nm.roots).reduce((a,b)=>a+b, 0);
            const isMortal = totalRoots === 0;

            if (isMortal) {
                nm.realm = Realm.Mortal;
            } else if (nm.age >= 6) { // 6岁后开始修炼
                if (nm.assignment === 'Cultivation') {
                    // 修炼速度受资质加成
                    const speed = (nm.aptitude / 5) + 2;
                    nm.cultivationProgress += speed;
                    if (nm.cultivationProgress >= 100) {
                        nm.cultivationProgress = 0;
                        if (nm.subRealm < 9) {
                            nm.subRealm += 1;
                        } else {
                            const idx = REALM_ORDER.indexOf(nm.realm);
                            if (idx < REALM_ORDER.length - 1) {
                                nm.realm = REALM_ORDER[idx + 1];
                                nm.subRealm = 1;
                                nm.maxAge += 120; // 突破增加大量寿元
                                yearLogs.push(`【突破】${nm.name} 踏入 ${nm.realm} 境界，寿元大增！`);
                            }
                        }
                    }
                }
            }

            if (nm.age >= nm.maxAge) {
                nm.status = 'dead';
                nm.deathYear = state.year;
                yearLogs.push(`【陨落】${nm.realm === Realm.Mortal ? '族人' : '长辈'} ${nm.name} (${nm.age}岁) 寿终正寝。`);
            }
            return nm;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers });

        setState(prev => {
            const newHerbs = { ...prev.inventory.herbs };
            Object.entries(bonusHerbs).forEach(([name, count]) => {
                newHerbs[name] = (newHerbs[name] || 0) + count;
            });
            return {
                ...prev,
                year: prev.year + 1,
                members: updatedMembers,
                buildings: updatedBuildings,
                spiritStones: prev.spiritStones + stoneGain,
                inventory: { ...prev.inventory, herbs: newHerbs },
                logs: [...yearLogs, ...prev.logs].slice(0, 15)
            };
        });
        setEvent(newEvent);
        setIsProcessing(false);
    };

    return (
        <div className="h-screen w-screen flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl">
                <div className="flex items-center gap-12">
                    <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>📜 族谱</button>
                    <button onClick={handleNextYear} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">{isProcessing ? '推演中' : '岁过一载'}</button>
                </div>
            </header>
            <main className="flex-1 flex overflow-hidden">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap regions={state.regions} members={state.members} currentRegionId={state.currentRegionId} onSelectRegion={(r) => setState(p => ({ ...p, currentRegionId: r ? r.id : '' }))} onUpdateMember={handleUpdateMember} onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} />
                    <div className={`absolute bottom-6 left-6 transition-all duration-500 parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-56'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5">
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)} className="text-[#4a3728] hover:text-black">{isConsoleCollapsed ? '▲' : '▼'}</button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-2.5 text-[11px]">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold"><span className="text-[#8b0000] mr-2">◈</span> {log}</p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
                {isDashboardVisible && <div className="w-80 h-full border-l border-yellow-900/50"><ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={handleAddMember} /></div>}
            </main>
            {isManagementVisible && <ClanManagement state={state} onUpdateMember={handleUpdateMember} onAddBuilding={handleAddBuilding} onAssignBuilding={handleAssignBuilding} onClose={() => setIsManagementVisible(false)} />}
            {event && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-[#f4e4bc] w-full max-w-2xl p-8 rounded border-[12px] border-[#4a3728] shadow-2xl relative">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 py-3 rounded-b-xl font-cursive text-2xl">{event.title}</div>
                        <div className="text-[#2c1810] leading-relaxed text-lg font-serif italic mb-8">{event.content}</div>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceA.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceB.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo, useCallback } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType } from '../types';
import { TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, POSITIONS, PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
}

const ITEMS_PER_PAGE = 8;

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan'>('attr');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedLibraryMethodId, setFocusedLibraryMethodId] = useState<string | null>(null);

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const getGradeColor = (grade: number) => {
        if (grade <= 2) return 'border-slate-300 text-slate-100 bg-slate-500/10 shadow-[0_0_5px_rgba(255,255,255,0.1)]';
        if (grade <= 4) return 'border-emerald-500 text-emerald-400 bg-emerald-500/10 shadow-[0_0_8px_rgba(16,185,129,0.2)]';
        if (grade <= 6) return 'border-sky-500 text-sky-400 bg-sky-500/10 shadow-[0_0_10px_rgba(14,165,233,0.3)]';
        if (grade === 7) return 'border-orange-500 text-orange-400 bg-orange-500/10 shadow-[0_0_12px_rgba(249,115,22,0.4)]';
        if (grade === 8) return 'border-yellow-500 text-yellow-400 bg-yellow-500/10 shadow-[0_0_15px_rgba(234,179,8,0.5)]';
        return 'border-rose-600 text-rose-500 bg-rose-600/10 shadow-[0_0_20px_rgba(244,63,94,0.6)] animate-pulse';
    };

    const getGradeText = (method: CultivationMethod) => {
        const numerals = ['','一','二','三','四','五','六','七','八','九'];
        return `${numerals[method.grade]}品${method.quality}`;
    };

    const toggleMethod = (methodId: string, type: MethodType) => {
        if (!selectedMember) return;

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
        setFocusedLibraryMethodId(null);
    };

    const getElementColorClass = (key: string, val: number) => {
        if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
        switch (key) {
            case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
            case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
            case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
            case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
            case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
            default: return 'text-gray-400 border-gray-500';
        }
    };

    const getElementName = (key: string) => {
        switch (key) {
            case 'gold': return '金';
            case 'wood': return '木';
            case 'water': return '水';
            case 'fire': return '火';
            case 'earth': return '土';
            default: return key;
        }
    };

    const libraryMethods = useMemo(() => {
        return CULTIVATION_METHODS.filter(m => m.type === libraryType);
    }, [libraryType]);

    // Global Tooltip Management
    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;

        // Smart Positioning
        if (rect.top < 300) {
            y = rect.bottom + 12;
        } else {
            y = rect.top - 12;
        }

        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;

        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                    {getGradeText(method)}
                </span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-400 mb-3 leading-relaxed italic">{method.desc}</p>
        </div>
    );

    const renderPhysiqueTooltipContent = (physique: string) => (
        <div className="w-48 text-pink-200 font-serif">
            <p className="font-bold border-b border-pink-900/30 mb-1 pb-1 text-sm">【{physique}】</p>
            <p className="text-xs italic leading-relaxed">{PHYSIQUE_DETAILS[physique] || '暂无详细记载。'}</p>
        </div>
    );

    const renderSlotItem = (methodId: string | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;

        return (
            <div className="flex flex-col items-center gap-1 group">
                <div 
                    onClick={() => methodId && setFocusedSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => method && showTooltip(e, renderMethodTooltipContent(method))}
                    onMouseLeave={hideTooltip}
                    className={`relative cursor-pointer transition-all duration-300 rounded flex items-center justify-center 
                        ${type === 'Cultivation' ? 'w-16 h-16 sm:w-24 sm:h-24 border-4 border-yellow-600/20' : 'w-12 h-12 sm:w-16 sm:h-16 border-2 border-yellow-900/20'} 
                        bg-black/50 overflow-hidden hover:border-yellow-500/50`}
                >
                    {method ? (
                        <div className={`w-full h-full border-2 p-1 flex flex-col items-center justify-center text-center font-bold ${getGradeColor(method.grade)}`}>
                            <span className={type === 'Cultivation' ? 'text-[10px] sm:text-xs' : 'text-[7px] sm:text-[8px]'}>{method.name}</span>
                        </div>
                    ) : (
                        <div className="text-gray-800 text-[8px] sm:text-[10px] opacity-40 italic">{label}</div>
                    )}
                </div>
                <span className="text-[8px] sm:text-[10px] text-yellow-700/80 font-bold bg-black/30 px-2 sm:px-3 py-0.5 rounded-full border border-yellow-900/10">{label}</span>
            </div>
        );
    };

    return (
        <div className="bg-[#1e130c] border-l-4 border-yellow-800 h-full flex flex-col relative overflow-hidden font-serif shadow-2xl">
            {tooltip && tooltip.visible && (
                <div 
                    className="fixed z-[10000] pointer-events-none bg-black/95 border-2 border-yellow-900/50 p-4 rounded shadow-[0_10px_40px_rgba(0,0,0,0.8)] backdrop-blur-md animate-fade-in"
                    style={{ left: tooltip.x, top: tooltip.y, transform: `translate(-50%, ${tooltip.y > window.innerHeight / 2 ? '-100%' : '0'})` }}
                >
                    {tooltip.content}
                </div>
            )}

            <div className="p-4 border-b border-yellow-900/30 bg-black/40 shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-cursive text-yellow-500">⛩️ 族谱常青</h2>
                    <span className="text-[10px] text-yellow-700 bg-black/50 px-3 py-1 rounded-full border border-yellow-900/20">
                        底蕴: {state.heritagePool}
                    </span>
                </div>
                <div className="flex p-1 bg-black/40 rounded-lg gap-1 border border-yellow-900/10">
                    <button onClick={() => handleTabChange('alive')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'alive' ? 'bg-yellow-800 text-yellow-100 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>在世族人</button>
                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500 hover:text-gray-300'}`}>英灵祠堂</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2 scrollbar-hide">
                {activeTab === 'alive' && (
                    <button onClick={onAddMember} className="w-full bg-green-900/20 hover:bg-green-800/40 text-green-400 border border-green-900/50 py-2 rounded text-xs transition-all flex items-center justify-center gap-2 mb-4 group">
                        <span>👶</span> 诞育麟儿
                    </button>
                )}
                {pagedMembers.length > 0 ? pagedMembers.map(member => {
                    const isYoung = member.age < 6;
                    return (
                        <div 
                            key={member.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(member.id)}
                            className={`group p-3 rounded-md border transition-all cursor-pointer ${selectedMemberId === member.id ? 'bg-[#2d1e15] border-yellow-600 scale-[1.02] shadow-xl' : 'bg-[#1e130c] border-yellow-900/30 hover:border-yellow-700/50'}`}
                        >
                            <div className="flex justify-between items-center mb-1">
                                <div className="flex items-center gap-2">
                                    <span className="font-bold text-sm text-yellow-100/90">{member.name}</span>
                                    <span className="text-[8px] text-orange-400 opacity-60">[{member.position}]</span>
                                </div>
                                <span className={`text-[9px] px-1.5 py-0.5 rounded-sm bg-yellow-900/40 text-yellow-500 border border-yellow-700/20`}>
                                    {isYoung ? '幼童' : member.realm}
                                </span>
                            </div>
                            <div className="flex justify-between text-[10px] text-gray-500">
                                <span>{member.age} 岁</span>
                                <span className="text-[9px] opacity-70 italic">{member.realm === Realm.Mortal && member.age >= 6 ? '凡胎' : member.rootGrade}</span>
                            </div>
                        </div>
                    );
                }) : (
                    <div className="py-20 text-center text-gray-700 opacity-40 italic">空空如也</div>
                )}
            </div>

            {selectedMember && activeTab === 'alive' && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 p-2 sm:p-4 font-serif overflow-hidden">
                    <div className="relative w-full max-w-6xl max-h-[95vh] h-full bg-[#1a2521] border-[4px] sm:border-[12px] border-[#2c3e34] rounded-sm shadow-2xl overflow-hidden flex flex-col">
                        <div className="h-24 sm:h-28 bg-[#141e1b] border-b border-[#2c3e34] flex items-center px-2 sm:px-8 shrink-0 pt-4 sm:pt-6">
                            <div className="flex items-center gap-1 sm:gap-2 h-full overflow-x-auto scrollbar-hide">
                                <button onClick={() => setDetailTab('attr')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'attr' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>👤 属性</button>
                                <button onClick={() => setDetailTab('talents')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'talents' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>📜 天赋</button>
                                {selectedMember.realm !== Realm.Mortal && (
                                    <>
                                        <button onClick={() => setDetailTab('cultivation')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'cultivation' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🌀 功法</button>
                                        <button onClick={() => setDetailTab('plan')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'plan' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🗺️ 计划</button>
                                    </>
                                )}
                                <button onClick={() => setDetailTab('tasks')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'tasks' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🎯 指派</button>
                            </div>
                            <button onClick={() => setSelectedMemberId(null)} className="ml-auto min-w-[40px] w-10 h-10 bg-red-900/20 hover:bg-red-900/40 text-red-500 rounded-full flex items-center justify-center text-2xl transition-all font-bold mt-[-8px]">×</button>
                        </div>

                        <div className="flex-1 p-4 sm:p-6 lg:p-12 overflow-y-auto custom-scrollbar bg-[#1a2521]/50">
                            {detailTab === 'attr' && (
                                <div className="space-y-8 animate-fade-in">
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                        <div>
                                            <h4 className="text-yellow-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-yellow-900/10 pb-2 mb-4">核心元气</h4>
                                            <div className="grid grid-cols-2 gap-4 text-xs sm:text-sm">
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">性别：</span><span className="text-gray-300 font-bold">{selectedMember.gender}</span></div>
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">年龄：</span><span className="text-gray-300 font-bold">{selectedMember.age} 岁</span></div>
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">寿元：</span><span className={`font-bold ${selectedMember.maxAge - selectedMember.age < 5 ? 'text-red-500' : 'text-green-400'}`}>{selectedMember.age} / {selectedMember.maxAge}</span></div>
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">身份：</span><span className="text-orange-400 font-bold">{selectedMember.realm === Realm.Mortal ? '凡人' : '修仙者'}</span></div>
                                            </div>
                                        </div>
                                        <div>
                                            <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">天赋禀赋</h4>
                                            <div className="grid grid-cols-2 gap-4 text-xs sm:text-sm">
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">资质：</span><span className="text-yellow-500 font-bold">{selectedMember.aptitude}</span></div>
                                                <div className="flex justify-between border-b border-white/5 pb-2"><span className="text-gray-500">灵根：</span><span className="text-blue-400 font-bold">{selectedMember.age < 6 ? '尚未觉醒' : selectedMember.rootGrade}</span></div>
                                            </div>
                                        </div>
                                    </div>
                                    {selectedMember.realm !== Realm.Mortal && (
                                        <div>
                                            <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">修为：{selectedMember.realm} {selectedMember.subRealm}层</h4>
                                            <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10">
                                                <div className="h-full bg-blue-500" style={{ width: `${selectedMember.cultivationProgress}%` }}></div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )}
                            {detailTab === 'talents' && (
                                <div className="space-y-8 animate-fade-in text-white">
                                    <div>
                                        <h4 className="text-red-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-red-900/10 pb-2 mb-4">⚔️ 战斗造诣 (1-10)</h4>
                                        <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                                            {(Object.entries(selectedMember.talents.战斗天赋) as [string, number][]).map(([key, val]) => (
                                                <div key={key} className="bg-black/20 p-2 sm:p-3 rounded-lg border border-white/5 text-center">
                                                    <p className="text-[10px] text-gray-500">{key}</p>
                                                    <p className="text-lg font-bold text-red-400">{val}</p>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                    <div>
                                        <h4 className="text-blue-700 text-[10px] sm:text-xs font-bold uppercase tracking-[0.3em] border-b border-blue-900/10 pb-2 mb-4">🧪 百艺修持 (1-10)</h4>
                                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                                            {(Object.entries(selectedMember.talents.百艺天赋) as [string, number][]).map(([key, val]) => (
                                                <div key={key} className="bg-black/30 p-4 rounded-lg border border-blue-900/20 relative group overflow-hidden">
                                                    <div className="flex justify-between items-center mb-2">
                                                        <span className="text-xs text-gray-400">{key}</span>
                                                        <span className="text-xl font-bold text-blue-400">{val}</span>
                                                    </div>
                                                    <p className="text-sm font-bold text-yellow-500">{getArtisanTitle(key, val, selectedMember.realm)}</p>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            )}
                            {detailTab === 'tasks' && (
                                <div className="space-y-2 animate-fade-in max-w-xl mx-auto">
                                    {(Object.keys(TASK_INFO) as TaskType[]).map(task => {
                                        // 凡人不能执行闭关
                                        if (selectedMember.realm === Realm.Mortal && task === 'Cultivation') return null;
                                        return (
                                            <button
                                                key={task}
                                                onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                className={`w-full p-4 rounded-lg border transition-all text-left ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100' : 'bg-black/20 border-white/5 text-gray-500'}`}
                                            >
                                                <p className="text-sm font-bold">{TASK_INFO[task].label}</p>
                                                <p className="text-[10px] opacity-60">{TASK_INFO[task].desc}</p>
                                            </button>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;
